apiVersion: v1
data:
  default.conf.template: |
    server {
        listen 80;
        location = /healthz {
            return 200 "ok\n";
            access_log off;
        }
        location / {
            proxy_pass ${REQUIRED_API_BASE};
        }
    }
kind: ConfigMap
metadata:
  labels:
    kustomize.toolkit.fluxcd.io/name: flux-system
    kustomize.toolkit.fluxcd.io/namespace: flux-system
  name: vigil-app-nginx-config
  namespace: default

parts.args:
{"title":"fix: Correct invalid nginx image tag in vigil-app Deployment","body":"**Root Cause:** Declared Deployment manifest specifies invalid image tag 'nginx:declared-missing' that does not exist in the registry, causing new ReplicaSet pods to fail with ImagePullBackOff.

**Evidence:** Pod/vigil-app-67cd9d8bb8-lthzl event: "Failed to pull image 'nginx:live-missing': rpc error: code = NotFound desc = failed to pull and unpack image 'docker.io/library/nginx:live-missing': docker.io/library/nginx:live-missing: not found"

**Fix:** Updated image tag from 'nginx:declared-missing' to 'nginx:stable' in the Deployment manifest."}
